import { useState, useEffect } from "react"
import { BrowserRouter, Routes, Route, Navigate } from "react-router-dom"
import { api } from "@/lib/api"
import { ProjectCockpit } from "@/modules/ops/ui/ProjectCockpit"
import { ProjectBoard } from "@/modules/ops/ui/ProjectBoard"
import { FinancialDashboard } from "@/modules/fin/ui/FinancialDashboard"
// Removed AnalyticsDashboard import
// Removed LoginForm import (we redirect to Hub now)
// Removed AppSwitcher import
import { ErpTabBar } from "@/components/layout/ErpTabBar"
import { ExecutiveLayout } from "@/views/executive/ExecutiveLayout"
import { OpsLayout } from "@/views/ops/OpsLayout"
import { CommercialLayout } from "@/views/commercial/CommercialLayout"
import CommercialPipeline from "@/modules/commercial/ui/CommercialPipeline"
import { MissionControl } from "@/modules/commercial/ui/MissionControl"
import CommercialPerformance from "@/views/commercial/CommercialPerformance"
import ClientsView from "@/views/commercial/ClientsView"
import { ContractsView } from "@/views/commercial/ContractsView"
import { GanttMatrixView } from "@/modules/ops/ui/GanttMatrixView"
import { KanbanView } from "@/modules/ops/ui/KanbanView"
import { PeopleView } from "@/modules/ops/ui/PeopleView"
import WorkloadView from "@/modules/ops/ui/WorkloadView"
import { StrategyManagerView } from "@/modules/strategy/ui/StrategyManagerView"
import { ExecutiveDashboard } from "@/views/executive/ExecutiveDashboard"
import { PortfolioView } from "@/views/executive/PortfolioView"
import { BIView } from "@/views/executive/BIView"

import { StrategyReviewView } from "@/modules/strategy/ui/StrategyReviewView"
import { AuditTrailView } from "@/views/executive/AuditTrailView"
import { ApprovalCenterView } from "@/views/executive/ApprovalCenterView"

// Funв”њВєв”њГЃes e Wrappers Legados de APPs e Extranets foram removidas para Micro-frontends.

function App() {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean | null>(null);

  useEffect(() => {
    const initSilentAuth = async () => {
      // 1. Tenta Auth via Storage herdado (Compatibilidade Temporal)
      const token = localStorage.getItem("token");
      if (token) {
        setIsAuthenticated(true);
        return;
      }

      // 2. В­Ж’ГёГ­ВґВ©Г… SSO Auth Bridge (Fase 13): "Recuperaв”њВєв”њГєo Cega"
      // Se nв”њГєo hв”њГ­ token, pede ao server para verificar se hв”њГ­ Cookie vв”њГ­lido
      try {
        await api.get("/iam/me");
        setIsAuthenticated(true);
      } catch (error) {
        // Redireciona o usuв”њГ­rio rejeitado direto para o Hub Central
        window.location.href = import.meta.env.VITE_HUB_URL || "http://localhost:5175";
      }
    };

    initSilentAuth();
  }, []);

  const logout = () => {
    localStorage.removeItem("token");
    setIsAuthenticated(false);
    window.location.href = import.meta.env.VITE_HUB_URL || "http://localhost:5175";
  };

  // Tela preta rв”њГ­pida de transiв”њВєв”њГєo do SSO para evitar Flashes
  if (isAuthenticated === null) {
      return (
        <div className="h-screen w-screen flex flex-col items-center justify-center bg-[#050510]">
            <div className="w-10 h-10 border-4 border-indigo-500 border-t-transparent rounded-full animate-spin mb-4"></div>
            <p className="text-slate-500 text-xs tracking-widest uppercase font-semibold">Validando Sessв”њГєo Segura...</p>
        </div>
      );
  }

  if (!isAuthenticated) return null;

  return (
    <BrowserRouter>
      {/* BARRA DE ABAS GLOBAL FIXA NO RODAPв”њГ« */}
      <ErpTabBar onLogout={logout} />

      <div className="pb-12 h-screen overflow-hidden">
        <Routes>
          {/* PORTAL DE ENTRADA (Agora redireciona para a primeira Aba do ERP: Gestв”њГєo) */}
          <Route path="/" element={<Navigate to="/executive/overview" replace />} />

        {/* VIEW 1: EXECUTIVE (BI & FIN) */}
        <Route path="/executive" element={<ExecutiveLayout />}>
          <Route path="overview" element={<ExecutiveDashboard />} />
          <Route path="strategy" element={<StrategyManagerView />} />
          <Route path="portfolio" element={<PortfolioView />} />
          <Route path="people" element={<PeopleView />} />
          <Route path="financial" element={<FinancialDashboard />} />
          <Route path="audit" element={<AuditTrailView />} />
          <Route path="analytics" element={<BIView />} />
          <Route index element={<Navigate to="overview" />} />
        </Route>

        {/* VIEW 2: COMMERCIAL */}
        <Route path="/commercial" element={<CommercialLayout />}>
          <Route path="pipeline" element={<CommercialPipeline />} />
          <Route path="missions" element={<MissionControl />} />
          <Route path="performance" element={<CommercialPerformance />} />
          <Route path="clients" element={<ClientsView />} />
          <Route path="contracts" element={<ContractsView />} />
          <Route index element={<Navigate to="pipeline" />} />
        </Route>

        {/* VIEW 3: OPS (FACTORY) */}
        <Route path="/ops" element={<OpsLayout />}>
          <Route path="cockpit" element={<ProjectCockpit />} />
          <Route path="portfolio" element={<ProjectBoard />} />
          <Route path="kanban" element={<KanbanView />} />
          <Route path="gantt" element={<GanttMatrixView />} />
          <Route path="workload" element={<WorkloadView />} />
          <Route path="strategy" element={<StrategyReviewView />} />
          <Route path="approvals" element={<ApprovalCenterView />} />
          <Route path="issues" element={<div className="p-8 text-center text-slate-500">Gestв”њГєo de Gargalos (Em breve)</div>} />
          <Route path="map" element={<div className="p-8 text-center text-slate-500">Mapa Operacional (Em breve)</div>} />
          <Route index element={<Navigate to="cockpit" />} />
        </Route>

        {/* Academy e Portais Extranet removidos na migraв”њВєв”њГєo de Arquitetura. */}

        {/* Fallback */}
        <Route path="*" element={<Navigate to="/executive/overview" replace />} />
      </Routes>
      </div>
    </BrowserRouter>
  )
}

export default App

import * as React from "react"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const badgeVariants = cva(
  "inline-flex items-center rounded-md border px-2.5 py-0.5 text-xs font-semibold transition-colors focus:outline-none focus:ring-2 focus:ring-ring focus:ring-offset-2",
  {
    variants: {
      variant: {
        default:
          "border-transparent bg-primary text-primary-foreground shadow hover:bg-primary/80",
        secondary:
          "border-transparent bg-secondary text-secondary-foreground hover:bg-secondary/80",
        destructive:
          "border-transparent bg-destructive text-destructive-foreground shadow hover:bg-destructive/80",
        outline: "text-foreground",
      },
    },
    defaultVariants: {
      variant: "default",
    },
  }
)

export interface BadgeProps
  extends React.HTMLAttributes<HTMLDivElement>,
    VariantProps<typeof badgeVariants> {}

function Badge({ className, variant, ...props }: BadgeProps) {
  return (
    <div className={cn(badgeVariants({ variant }), className)} {...props} />
  )
}

export { Badge, badgeVariants }

import * as React from "react"
import { Slot } from "@radix-ui/react-slot"
import { cva, type VariantProps } from "class-variance-authority"

import { cn } from "@/lib/utils"

const buttonVariants = cva(
  "inline-flex items-center justify-center gap-2 whitespace-nowrap rounded-md text-sm font-medium transition-colors focus-visible:outline-none focus-visible:ring-1 focus-visible:ring-ring disabled:pointer-events-none disabled:opacity-50 [&_svg]:pointer-events-none [&_svg]:size-4 [&_svg]:shrink-0",
  {
    variants: {
      variant: {
        default:
          "bg-primary text-primary-foreground shadow hover:bg-primary/90",
        destructive:
          "bg-destructive text-destructive-foreground shadow-sm hover:bg-destructive/90",
        outline:
          "border border-input bg-background shadow-sm hover:bg-accent hover:text-accent-foreground",
        secondary:
          "bg-secondary text-secondary-foreground shadow-sm hover:bg-secondary/80",
        ghost: "hover:bg-accent hover:text-accent-foreground",
        link: "text-primary underline-offset-4 hover:underline",
      },
      size: {
        default: "h-9 px-4 py-2",
        sm: "h-8 rounded-md px-3 text-xs",
        lg: "h-10 rounded-md px-8",
        icon: "h-9 w-9",
      },
    },
    defaultVariants: {
      variant: "default",
      size: "default",
    },
  }
)

export interface ButtonProps
  extends React.ButtonHTMLAttributes<HTMLButtonElement>,
    VariantProps<typeof buttonVariants> {
  asChild?: boolean
}

const Button = React.forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant, size, asChild = false, ...props }, ref) => {
    const Comp = asChild ? Slot : "button"
    return (
      <Comp
        className={cn(buttonVariants({ variant, size, className }))}
        ref={ref}
        {...props}
      />
    )
  }
)
Button.displayName = "Button"

export { Button, buttonVariants }

import { api } from '../api';
import { Mission, Lead, Opportunity, CreateDealPayload, OpportunityStatus } from '../../modules/commercial/types';

export const commercialApi = {
  // Missions
  getMissions: async (status?: string): Promise<Mission[]> => {
    const res = await api.get(`/commercial/missions`, { params: { status } });
    return res.data;
  },

  getMissionById: async (id: string): Promise<Mission> => {
    const res = await api.get(`/commercial/missions/${id}`);
    return res.data;
  },

  // Leads
  getLeads: async (missionId?: string): Promise<Lead[]> => {
    const res = await api.get(`/commercial/leads`, { params: { missionId } });
    return res.data;
  },

  // Opportunities (Deals)
  createDeal: async (data: CreateDealPayload): Promise<Opportunity> => {
    const res = await api.post(`/commercial/opportunities`, data);
    return res.data;
  },

  updateDealStatus: async (dealId: string, status: OpportunityStatus, technicalProposal?: any): Promise<Opportunity> => {
    const res = await api.put(`/commercial/opportunities/${dealId}`, {
      status,
      technicalProposal
    });
    return res.data;
  },

  getDeals: async (missionId?: string): Promise<Opportunity[]> => {
    const res = await api.get(`/commercial/opportunities`, { params: { missionId } });
    return res.data;
  }
};

import React, { createContext, useContext, useState, ReactNode } from 'react';
import { Mission, Lead } from '../types';

interface CommercialContextType {
  activeMission: Mission | null;
  setActiveMission: (mission: Mission | null) => void;
  selectedLead: Lead | null;
  setSelectedLead: (lead: Lead | null) => void;
  isLeadDrawerOpen: boolean;
  setIsLeadDrawerOpen: (open: boolean) => void;
}

const CommercialContext = createContext<CommercialContextType | undefined>(undefined);

export const CommercialProvider: React.FC<{ children: ReactNode }> = ({ children }) => {
  const [activeMission, setActiveMission] = useState<Mission | null>(null);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [isLeadDrawerOpen, setIsLeadDrawerOpen] = useState(false);

  const handleSetSelectedLead = (lead: Lead | null) => {
      setSelectedLead(lead);
      if (lead) setIsLeadDrawerOpen(true);
      else setIsLeadDrawerOpen(false);
  };

  return (
    <CommercialContext.Provider value={{
      activeMission,
      setActiveMission,
      selectedLead,
      setSelectedLead: handleSetSelectedLead,
      isLeadDrawerOpen,
      setIsLeadDrawerOpen
    }}>
      {children}
    </CommercialContext.Provider>
  );
};

export const useCommercial = () => {
  const context = useContext(CommercialContext);
  if (!context) {
    throw new Error('useCommercial must be used within a CommercialProvider');
  }
  return context;
};

export type MissionStatus = 'PLANNING' | 'ACTIVE' | 'COMPLETED';
export type OpportunityStatus = 
  | 'LEAD_QUALIFICATION'
  | 'VISIT_SCHEDULED'
  | 'TECHNICAL_VISIT_DONE'
  | 'PROPOSAL_GENERATED'
  | 'NEGOTIATION'
  | 'CONTRACT_SENT'
  | 'CLOSED_WON'
  | 'CLOSED_LOST';

export type LeadSource = 'ORGANIC' | 'REFERRAL' | 'PAID_MEDIA' | 'ACADEMY' | 'OUTBOUND';

export interface Mission {
  id: string;
  name: string;
  region: string;
  regionPolygon?: any; // JSON
  startDate: string; // ISO Date
  endDate: string;
  status: MissionStatus;
  stats?: {
    totalLeads: number;
    converted: number;
    potentialValue: number;
  };
  coordinatorId?: string;
  tenantId: string;
}

export interface Lead {
  id: string;
  name: string;
  email?: string;
  phone: string;
  status: string; // 'NEW' | 'HOT' | 'CONVERTED' etc
  source?: LeadSource;
  academyScore: number;
  city?: string;
  state?: string;
  missionId?: string;
  tenantId: string;
  notes?: string;
  interactions?: LeadInteraction[];
}

export interface LeadInteraction {
  id: string;
  type: string;
  content: string;
  date: string;
}

export interface TechnicalProposal {
  id: string;
  kitData: Record<string, any>;
  consumptionAvg: number;
  infrastructurePhotos: string[]; // URLs
  paybackData: Record<string, any>;
  validatedByEng: boolean;
}

export interface Opportunity {
  id: string;
  title: string;
  leadId: string;
  lead?: Lead;
  missionId?: string;
  mission?: Mission;
  status: OpportunityStatus;
  estimatedValue: number;
  probability: number;
  technicalProposal?: TechnicalProposal;
  tenantId: string;
  createdAt: string;
  updatedAt: string;
}

export interface CreateDealPayload {
  title: string;
  leadId: string;
  missionId?: string;
  estimatedValue: number;
  status: OpportunityStatus;
}

import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { X, User, Phone, Mail, MapPin } from 'lucide-react';
import { Button } from '@/components/ui/mock-components';
import { api } from '@/lib/api';

const clientSchema = z.object({
    name: z.string().min(3, 'Nome deve ter no mв”њВЎnimo 3 caracteres'),
    email: z.string().email('Email invв”њГ­lido').optional().or(z.literal('')),
    phone: z.string().min(10, 'Telefone invв”њГ­lido'),
    city: z.string().optional(),
    state: z.string().length(2, 'Estado deve ter 2 letras').optional().or(z.literal('')),
    notes: z.string().optional(),
});

type ClientFormValues = z.infer<typeof clientSchema>;

interface ClientDrawerProps {
    isOpen: boolean;
    onClose: () => void;
    onSuccess: () => void;
    client?: any; // If editing an existing client
    defaultStatus?: string;
    title?: string;
}

export const ClientDrawer: React.FC<ClientDrawerProps> = ({
    isOpen,
    onClose,
    onSuccess,
    client,
    defaultStatus,
    title
}) => {
    const { register, handleSubmit, reset, formState: { errors, isSubmitting } } = useForm<ClientFormValues>({
        resolver: zodResolver(clientSchema),
        defaultValues: {
            name: '',
            email: '',
            phone: '',
            city: '',
            state: '',
            notes: '',
        }
    });

    useEffect(() => {
        if (client && isOpen) {
            reset({
                name: client.name || '',
                email: client.email || '',
                phone: client.phone || '',
                city: client.city || '',
                state: client.state || '',
                notes: client.notes || '',
            });
        } else if (isOpen) {
            reset({
                name: '',
                email: '',
                phone: '',
                city: '',
                state: '',
                notes: '',
            });
        }
    }, [client, isOpen, reset]);

    if (!isOpen) return null;

    const onSubmit = async (data: ClientFormValues) => {
        try {
            const payload = {
                ...data,
                status: defaultStatus || 'CONVERTED', // Force status to CONVERTED for Clients if not provided
                source: 'OTHER'
            };

            if (client?.id) {
                await api.put(`/commercial/leads/${client.id}`, payload);
            } else {
                await api.post(`/commercial/leads`, payload);
            }

            reset();
            onSuccess();
            onClose();
        } catch (error) {
            console.error('Failed to save client', error);
            alert('Erro ao salvar cliente. Verifique o console.');
        }
    };

    return (
        <div className="fixed inset-0 z-50 flex justify-end">
            {/* Backdrop */}
            <div className="absolute inset-0 bg-black/30 backdrop-blur-sm" onClick={onClose} />

            {/* Drawer */}
            <div className="relative w-full max-w-md bg-white dark:bg-slate-900 shadow-2xl h-full flex flex-col animate-in slide-in-from-right duration-300">

                {/* Header */}
                <div className="p-6 border-b border-slate-100 dark:border-slate-800 flex justify-between items-center bg-slate-50/50 dark:bg-slate-800/50">
                    <div>
                        <h2 className="text-xl font-bold text-slate-800 dark:text-white">
                            {title ? title : (client ? 'Editar Cliente' : 'Novo Cliente')}
                        </h2>
                    </div>
                    <button onClick={onClose} className="p-2 hover:bg-slate-200 rounded-full transition-colors text-slate-500">
                        <X size={20} />
                    </button>
                </div>

                {/* Form Content */}
                <div className="flex-1 overflow-y-auto p-6">
                    <form id="client-form" onSubmit={handleSubmit(onSubmit)} className="space-y-6">

                        <div className="space-y-4">
                            <h3 className="text-sm font-semibold text-slate-800 dark:text-slate-200 flex items-center gap-2">
                                <User size={16} className="text-purple-600" />
                                Dados Principais
                            </h3>

                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                                    Nome Completo *
                                </label>
                                <input
                                    type="text"
                                    {...register('name')}
                                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 text-slate-800 dark:text-slate-200"
                                    placeholder="Ex: Joв”њГєo da Silva"
                                />
                                {errors.name && <p className="text-red-500 text-xs mt-1">{errors.name.message}</p>}
                            </div>

                            <div className="grid grid-cols-2 gap-4">
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                                        <Phone size={14} className="inline mr-1" /> Telefone *
                                    </label>
                                    <input
                                        type="text"
                                        {...register('phone')}
                                        className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 text-slate-800 dark:text-slate-200"
                                        placeholder="(00) 00000-0000"
                                    />
                                    {errors.phone && <p className="text-red-500 text-xs mt-1">{errors.phone.message}</p>}
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                                        <Mail size={14} className="inline mr-1" /> E-mail
                                    </label>
                                    <input
                                        type="email"
                                        {...register('email')}
                                        className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 text-slate-800 dark:text-slate-200"
                                        placeholder="email@exemplo.com"
                                    />
                                    {errors.email && <p className="text-red-500 text-xs mt-1">{errors.email.message}</p>}
                                </div>
                            </div>
                        </div>

                        <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                            <h3 className="text-sm font-semibold text-slate-800 dark:text-slate-200 flex items-center gap-2">
                                <MapPin size={16} className="text-purple-600" />
                                Localizaв”њВєв”њГєo
                            </h3>

                            <div className="grid grid-cols-3 gap-4">
                                <div className="col-span-2">
                                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                                        Cidade
                                    </label>
                                    <input
                                        type="text"
                                        {...register('city')}
                                        className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 text-slate-800 dark:text-slate-200"
                                        placeholder="Ex: Manaus"
                                    />
                                </div>
                                <div>
                                    <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                                        UF
                                    </label>
                                    <input
                                        type="text"
                                        {...register('state')}
                                        maxLength={2}
                                        className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 uppercase text-slate-800 dark:text-slate-200"
                                        placeholder="AM"
                                    />
                                    {errors.state && <p className="text-red-500 text-xs mt-1">{errors.state.message}</p>}
                                </div>
                            </div>
                        </div>

                        <div className="space-y-4 pt-4 border-t border-slate-100 dark:border-slate-800">
                            <div>
                                <label className="block text-sm font-medium text-slate-700 dark:text-slate-300 mb-1">
                                    Observaв”њВєв”њГЃes
                                </label>
                                <textarea
                                    {...register('notes')}
                                    rows={4}
                                    className="w-full bg-slate-50 dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg px-4 py-2 text-sm focus:outline-none focus:ring-2 focus:ring-purple-500 text-slate-800 dark:text-slate-200"
                                    placeholder="Informaв”њВєв”њГЃes adicionais sobre o cliente..."
                                />
                            </div>
                        </div>

                    </form>
                </div>

                {/* Footer Actions */}
                <div className="p-4 border-t border-slate-100 dark:border-slate-800 bg-slate-50 dark:bg-slate-900/50 flex gap-4">
                    <Button variant="outline" className="w-full" onClick={onClose} disabled={isSubmitting}>
                        Cancelar
                    </Button>
                    <Button
                        type="submit"
                        form="client-form"
                        className="w-full bg-purple-600 hover:bg-purple-700"
                        disabled={isSubmitting}
                    >
                        {isSubmitting ? 'Salvando...' : 'Salvar Dados'}
                    </Button>
                </div>
            </div>
        </div>
    );
};

import React, { useEffect, useState } from 'react';
import { LeadDrawer } from './LeadDrawer';
import { Plus, MoreHorizontal, Filter, Search, Loader2 } from 'lucide-react';
import { Button } from '@/components/ui/mock-components';
import { useDebounce } from '@/hooks/useDebounce';

import { Lead, Opportunity, OpportunityStatus } from '../types';

interface PipelineStage {
  id: string;
  name: string;
  order: number;
  color: string;
  helpText?: string;
}

// Map dynamic stage names to the strict backend OpportunityStatusEnum
const mapStageNameToStatus = (name: string): OpportunityStatus => {
  const map: Record<string, OpportunityStatus> = {
    'Lead': 'LEAD_QUALIFICATION',
    'Aguardando Vistoria': 'VISIT_SCHEDULED',
    'Vistoria': 'TECHNICAL_VISIT_DONE',
    'Proposta': 'PROPOSAL_GENERATED',
    'Negociaв”њВєв”њГєo': 'NEGOTIATION',
    'Contrato Fechado': 'CONTRACT_SENT',
    'Fechado': 'CLOSED_WON',
    'Concluв”њВЎdo': 'CLOSED_WON',
  };
  return map[name] || 'LEAD_QUALIFICATION'; // Fallback
};

export default function CommercialPipeline() {
  const [opportunities, setOpportunities] = useState<Opportunity[]>([]);
  const [stages, setStages] = useState<PipelineStage[]>([]);

  const [isLoading, setIsLoading] = useState(true);
  const [selectedLead, setSelectedLead] = useState<Lead | null>(null);
  const [isDrawerOpen, setIsDrawerOpen] = useState(false);
  const [draggedOppId, setDraggedOppId] = useState<string | null>(null);
  const [searchTerm, setSearchTerm] = useState("");
  const debouncedSearchTerm = useDebounce(searchTerm, 400);

  useEffect(() => {
    fetchData();
  }, []);

  const fetchData = async () => {
    try {
      const token = localStorage.getItem('token');
      // Fetch specifically Opportunities (Deals) and the dynamic Pipeline structure
      const [oppsRes, pipelineRes] = await Promise.all([
        fetch(`${import.meta.env.VITE_API_BASE_URL || "http://localhost:3001"}/api/v2/commercial/opportunities`, {
          headers: { 'Authorization': `Bearer ${token}` }
        }),
        fetch(`${import.meta.env.VITE_API_BASE_URL || "http://localhost:3001"}/api/v2/commercial/pipeline`, {
          headers: { 'Authorization': `Bearer ${token}` }
        })
      ]);

      const oppsData = await oppsRes.json();
      const pipelineData = await pipelineRes.json();

      if (oppsData.success) {
        setOpportunities(oppsData.data);
      }
      if (pipelineData.success && pipelineData.data?.stages) {
        setStages(pipelineData.data.stages);
      }

    } catch (error) {
      console.error("Failed to fetch opportunities or pipeline", error);
    } finally {
      setIsLoading(false);
    }
  };

  const updateOppStatus = async (oppId: string, newStatus: OpportunityStatus) => {
    // Optimistic UI update
    const previousOpps = [...opportunities];
    setOpportunities(prev => prev.map(o => o.id === oppId ? { ...o, status: newStatus } : o));

    try {
      const res = await fetch(`${import.meta.env.VITE_API_BASE_URL || "http://localhost:3001"}/api/v2/commercial/opportunities/${oppId}`, {
        method: 'PUT',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify({ status: newStatus })
      });

      const data = await res.json();
      if (!data.success) {
        alert(`Bloqueio de Guardrail:\n${data.error || 'Erro ao mover card.'}`);
        setOpportunities(previousOpps); // Revert on failure
      }
    } catch (error) {
      console.error("Failed to update status", error);
      setOpportunities(previousOpps); // Revert on failure
    }
  };

  const handleDragStart = (e: React.DragEvent, oppId: string) => {
    setDraggedOppId(oppId);
    e.dataTransfer.effectAllowed = 'move';
  };

  const handleDrop = (e: React.DragEvent, status: OpportunityStatus) => {
    e.preventDefault();
    if (!draggedOppId) return;

    // Call API (Guardrails will block invalid moves if needed)
    updateOppStatus(draggedOppId, status);
    setDraggedOppId(null);
  };

  const handleDragOver = (e: React.DragEvent) => {
    e.preventDefault();
  };

  const openDrawer = (opp: Opportunity) => {
    // LeadDrawer was built for Lead type, we pass the expanded Lead from Opportunity
    if (opp.lead) {
      setSelectedLead({ ...opp.lead, id: opp.leadId } as Lead);
      setIsDrawerOpen(true);
    }
  };

  // ... (handleInteraction same as before) ...
  const handleAddInteraction = async (type: string, content: string) => {
    if (!selectedLead) return;
    try {
      await fetch(`${import.meta.env.VITE_API_BASE_URL || "http://localhost:3001"}/api/v2/commercial/leads/${selectedLead.id}/interactions`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${localStorage.getItem('token')}`
        },
        body: JSON.stringify({ type, content })
      });
      // Refresh details logic
    } catch (error) {
      console.error(error);
    }
  };

  // Dynamic Geo-Clustering Detection
  const geoClusters = React.useMemo(() => {
    const cityCounts = opportunities
      .filter(o => o.status !== 'CLOSED_WON' && o.status !== 'CLOSED_LOST')
      .reduce((acc, opp) => {
        const city = opp.lead?.city?.trim();
        if (city) {
          acc[city] = (acc[city] || 0) + 1;
        }
        return acc;
      }, {} as Record<string, number>);

    // Find the city with the highest count that meets the threshold
    const criticalCity = Object.entries(cityCounts).find(([_, count]) => count >= 3);
    return criticalCity ? { city: criticalCity[0], count: criticalCity[1] } : null;
  }, [opportunities]);

  // Note: we now filter opportunities by debouncedSearchTerm instead of searchTerm
  const filteredOpps = React.useMemo(() => {
    return opportunities.filter(opp => {
      if (!debouncedSearchTerm) return true;
      const lowerSearch = debouncedSearchTerm.toLowerCase();
      const matchName = opp.title.toLowerCase().includes(lowerSearch);
      const matchLead = opp.lead?.name?.toLowerCase().includes(lowerSearch);
      return matchName || matchLead;
    });
  }, [opportunities, debouncedSearchTerm]);

  if (isLoading) return <div className="h-full flex items-center justify-center"><Loader2 className="animate-spin text-purple-600" /></div>;

  return (
    <div className="h-full flex flex-col">
      {/* Toolbar */}
      <div className="mb-6 flex justify-between items-center">
        <div className="flex gap-2">
          <div className="relative">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 h-4 w-4 text-slate-400" />
            <input
              type="text"
              placeholder="Buscar leads..."
              className="pl-10 pr-4 py-2 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 rounded-lg text-sm dark:text-slate-200 focus:outline-none focus:ring-2 focus:ring-purple-500 w-64"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <Button variant="outline" size="sm"><Filter className="h-4 w-4 mr-2" /> Filtros</Button>
        </div>
        <Button className="bg-purple-600 hover:bg-purple-700"><Plus className="h-4 w-4 mr-2" /> Novo Lead</Button>
      </div>

      {/* Board */}
      <div className="flex-1 overflow-x-auto pb-4">
        <div className="flex gap-4 h-full min-w-max">
          {stages.length === 0 && <p className="text-slate-500 text-sm p-4">Nenhum estв”њГ­gio de pipeline encontrado.</p>}
          {stages.map(stage => {
            const mappedStatus = mapStageNameToStatus(stage.name);
            return (
              <div
                key={stage.id}
                className="w-80 flex flex-col bg-slate-100 dark:bg-slate-900 rounded-xl border border-slate-200 dark:border-slate-800"
                onDragOver={handleDragOver}
                onDrop={(e) => handleDrop(e, mappedStatus)}
              >
                {/* Column Header */}
                <div className="p-3 border-b border-slate-200/50 dark:border-slate-800 relative group/header">
                  <div className="flex justify-between items-center mb-1">
                    <div className="flex items-center gap-2">
                      <div className={`w-2 h-2 rounded-full ${stage.color || 'bg-slate-500'}`}></div>
                      <span className="font-semibold text-slate-700 dark:text-slate-200 text-xs uppercase tracking-wider">{stage.name}</span>
                    </div>

                    {/* Column Dropdown Menu (Aesthetic / Functionality placeholder) */}
                    <div className="relative group/dropdown">
                      <MoreHorizontal size={14} className="text-slate-400 hover:text-slate-600 cursor-pointer transition-colors" />
                      <div className="absolute right-0 top-full mt-1 w-36 bg-white dark:bg-slate-800 border border-slate-200 dark:border-slate-700 shadow-lg rounded-md overflow-hidden opacity-0 invisible group-hover/dropdown:opacity-100 group-hover/dropdown:visible transition-all z-10">
                        <button className="w-full text-left px-3 py-2 text-xs text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700">Editar Estв”њГ­gio</button>
                        <button className="w-full text-left px-3 py-2 text-xs text-slate-600 dark:text-slate-300 hover:bg-slate-50 dark:hover:bg-slate-700">Ocultar Coluna</button>
                      </div>
                    </div>
                  </div>
                  {stage.helpText && <p className="text-[10px] text-slate-400 ml-4">{stage.helpText}</p>}

                  {/* Geo-Cluster Alert (Show in the first active qualification column if cluster exists) */}
                  {mappedStatus === 'LEAD_QUALIFICATION' && geoClusters && (
                    <div className="mt-2 bg-purple-100 dark:bg-purple-900/30 border border-purple-200 dark:border-purple-800/50 rounded-lg p-2 flex items-start gap-2">
                      <div className="bg-purple-500 text-white rounded-full p-1 mt-0.5"><Loader2 size={10} className="animate-spin" /></div>
                      <div>
                        <p className="text-xs font-bold text-purple-800 dark:text-purple-300">Cluster Detectado!</p>
                        <p className="text-[10px] text-purple-600 dark:text-purple-400 leading-tight">Vocв”њВ¬ tem {geoClusters.count} leads em {geoClusters.city}. <span className="underline cursor-pointer">Criar Missв”њГєo?</span></p>
                      </div>
                    </div>
                  )}
                </div>

                {/* Droppable Area */}
                <div className="flex-1 p-2 space-y-2 overflow-y-auto min-h-[100px]">
                  {filteredOpps
                    .filter(o => o.status === mappedStatus)
                    .map(opp => (
                      <div
                        key={opp.id}
                        draggable
                        onDragStart={(e) => handleDragStart(e, opp.id)}
                        onClick={() => openDrawer(opp)}
                        className="bg-white dark:bg-slate-800 p-3 rounded-lg border border-slate-200 dark:border-slate-700 shadow-sm cursor-grab hover:shadow-md transition-all active:cursor-grabbing group group-hover:border-purple-200 dark:group-hover:border-purple-500/50"
                      >
                        <div className="flex justify-between items-start mb-2">
                          {/* Opportunity specific title */}
                          <h4 className="font-bold text-slate-700 dark:text-slate-200 text-sm truncate">{opp.title}</h4>
                          {opp.lead?.engagementScore && opp.lead.engagementScore > 50 && <span className="text-[9px] font-bold text-orange-500 bg-orange-50 dark:bg-orange-900/20 px-1.5 py-0.5 rounded ml-2 shrink-0">HOT</span>}
                        </div>

                        <p className="text-xs text-slate-500 truncate mb-1">{opp.lead?.name || 'Sem Lide'}</p>
                        <p className="text-[10px] text-slate-400 truncate mb-3">{opp.lead?.city ? `${opp.lead.city} Г”Г‡Гі ` : ''}Valor: {new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(opp.estimatedValue || 0)}</p>

                        <div className="flex items-center justify-between mt-auto pt-2 border-t border-slate-50 dark:border-slate-700">
                          <div className="flex -space-x-1">
                            <div className="w-5 h-5 rounded-full bg-purple-100 dark:bg-purple-900/40 border border-white dark:border-slate-800 flex items-center justify-center text-[8px] font-bold text-purple-700 dark:text-purple-400">VE</div>
                          </div>
                          <span className="text-[9px] text-slate-400 font-medium">#{opp.id.slice(0, 5)}</span>
                        </div>
                      </div>
                    ))}
                </div>
              </div>
            )
          })}
        </div>
      </div>

      <LeadDrawer
        lead={selectedLead}
        isOpen={isDrawerOpen}
        onClose={() => setIsDrawerOpen(false)}
        onAddInteraction={handleAddInteraction}
      />
    </div>
  );
}

import { useEffect, useState } from "react";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/mock-components";
import { Users, TrendingUp, DollarSign, Sun, Loader2 } from "lucide-react";
import axios from "axios";
import { BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from "recharts";

interface FunnelData {
  status: string;
  _count: { id: number };
  _sum: { estimatedValue: number | null };
}

interface DashboardStats {
  totalLeads: number;
  funnelData: FunnelData[];
  revenue: {
    total: number;
    count: number;
  };
}

interface Activity {
  id: string;
  action: string;
  entity: string;
  details: string;
  timestamp: string;
  user?: { fullName: string };
}

export function MissionControl() {
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [activities, setActivities] = useState<Activity[]>([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    const fetchStats = async () => {
      try {
        const token = localStorage.getItem("token");
        const [statsRes, activitiesRes] = await Promise.all([
          axios.get(`${import.meta.env.VITE_API_BASE_URL || "http://localhost:3001"}/api/v2/commercial/opportunities/stats`, {
            headers: { Authorization: `Bearer ${token}` }
          }),
          axios.get(`${import.meta.env.VITE_API_BASE_URL || "http://localhost:3001"}/api/v2/commercial/activities`, {
            headers: { Authorization: `Bearer ${token}` }
          })
        ]);
        if (statsRes.data.success) {
          setStats(statsRes.data.data);
        }
        if (activitiesRes.data.success) {
          setActivities(activitiesRes.data.data);
        }
      } catch (err) {
        console.error("Erro ao carregar KPIs do Mission Control:", err);
      } finally {
        setLoading(false);
      }
    };
    fetchStats();
  }, []);

  if (loading) return <div className="p-8 flex items-center justify-center"><Loader2 className="animate-spin text-purple-600" /></div>;

  // Formatting helper
  const formatSec = (val: number) => new Intl.NumberFormat('pt-BR', { style: 'currency', currency: 'BRL' }).format(val || 0);

  // Prepare Chart Data mapping Enum to Readable Labels
  const chartData = stats?.funnelData.map(d => ({
    name: d.status.replace(/_/g, ' '),
    amount: d._count.id,
    value: d._sum.estimatedValue || 0
  })) || [];

  return (
    <div className="space-y-6">
      {/* 1. KPIs */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-4">
        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Leads na Base</CardTitle>
            <Users className="h-4 w-4 text-slate-400" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.totalLeads || 0}</div>
            <p className="text-xs text-slate-500">Mв”њВ®trica Global (SDR)</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Oportunidades (Pipeline)</CardTitle>
            <TrendingUp className="h-4 w-4 text-purple-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{stats?.funnelData.reduce((acc, curr) => acc + curr._count.id, 0) || 0}</div>
            <p className="text-xs text-purple-600 font-medium">Deals em andamento</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Receita Projetada (Total)</CardTitle>
            <Sun className="h-4 w-4 text-orange-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatSec(stats?.funnelData.reduce((acc, curr) => acc + (curr._sum.estimatedValue || 0), 0) || 0)}</div>
            <p className="text-xs text-orange-600 font-medium">Soma do pipeline</p>
          </CardContent>
        </Card>

        <Card>
          <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
            <CardTitle className="text-sm font-medium">Ganhos (Closed Won)</CardTitle>
            <DollarSign className="h-4 w-4 text-green-500" />
          </CardHeader>
          <CardContent>
            <div className="text-2xl font-bold">{formatSec(stats?.revenue.total || 0)}</div>
            <p className="text-xs text-green-600 font-medium">{stats?.revenue.count || 0} contratos fechados</p>
          </CardContent>
        </Card>
      </div>

      {/* 2. Pipeline Overview */}
      <div className="grid gap-4 md:grid-cols-2 lg:grid-cols-7">
        <Card className="col-span-4">
          <CardHeader>
            <CardTitle>Funil de Vendas (Oportunidades)</CardTitle>
          </CardHeader>
          <CardContent className="pl-2">
            <div className="h-[250px] w-full min-h-[250px] min-w-full">
              <ResponsiveContainer width="100%" height="100%">
                <BarChart data={chartData} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                  <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#E2E8F0" />
                  <XAxis dataKey="name" tick={{ fontSize: 10, fill: '#64748B' }} tickLine={false} axisLine={false} />
                  <YAxis tick={{ fontSize: 10, fill: '#64748B' }} tickLine={false} axisLine={false} />
                  <Tooltip
                    cursor={{ fill: '#F1F5F9' }}
                    contentStyle={{ borderRadius: '8px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                    formatter={(value: any) => [value, "Quantidade"]}
                  />
                  <Bar dataKey="amount" fill="#8B5CF6" radius={[4, 4, 0, 0]} barSize={40} />
                </BarChart>
              </ResponsiveContainer>
            </div>
          </CardContent>
        </Card>

        <Card className="col-span-3">
          <CardHeader>
            <CardTitle>Atividades Recentes</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {activities.length === 0 ? (
                <p className="text-sm text-slate-500">Sem atividades recentes.</p>
              ) : (
                activities.map(activity => (
                  <div key={activity.id} className="flex items-center">
                    <div className="h-9 w-9 rounded-full bg-blue-100 dark:bg-blue-900/40 flex items-center justify-center text-blue-600 dark:text-blue-400 font-bold text-xs mr-3 shrink-0">
                      {activity.user?.fullName?.substring(0, 2).toUpperCase() || 'SYS'}
                    </div>
                    <div className="space-y-1">
                      <p className="text-sm font-medium leading-none capitalize truncate max-w-[200px]" title={activity.action.replace(/_/g, ' ')}>
                        {activity.action.replace(/_/g, ' ').toLowerCase()}
                      </p>
                      <p className="text-xs text-slate-500 dark:text-slate-400 truncate max-w-[200px]" title={activity.details || activity.entity}>
                        {activity.details || activity.entity} Г”Г‡Гі {new Date(activity.timestamp).toLocaleDateString('pt-BR')}
                      </p>
                    </div>
                  </div>
                ))
              )}
            </div>
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

import { useEffect, useState, useCallback } from "react";
import { FinService, type Transaction, type BalanceSummary } from "../fin.service";
import { Card, Button, Input, Badge } from "@/components/ui/mock-components";
import { ArrowUpCircle, ArrowDownCircle, Wallet, Plus, Loader2, TrendingUp, AlertTriangle } from "lucide-react";
import { useForm } from "react-hook-form";
import {
    AreaChart,
    Area,
    XAxis,
    YAxis,
    CartesianGrid,
    Tooltip,
    ResponsiveContainer,
    Legend
} from 'recharts';

export function FinancialDashboard() {
