            await loadData(); // Refresh silencioso ou wrap com loading se preferir
        } catch {
            alert("Erro ao adicionar transaв”њВєв”њГєo");
        }
    }

    if (loading && !balance) {
        return <div className="p-8 flex justify-center"><Loader2 className="animate-spin" /></div>
    }

    return (
